form:Form.form:Scripts:
		function onChangeClase()
{
	if (Ctrl("oi_clase_org").GetXValue()=="")
	{
		Ctrl('treeESTR').loadFromString("<tree/>");
		Ctrl('treeESTR').SetXValue("");
	}

	var mp, nSQL, txtTree;

	np = new NomadProxy("", ut);
	nSQL = np.SQLService();

 	txtTree = nSQL.Get(Ctrl("main").getResource("qry:ESTRUCTURA"), "<PARAM oi_clase_org=\""+Ctrl("oi_clase_org").GetXValue()+"\" id=\""+Ctrl("treeESTR").GetXValue()+"\"/>");

	Ctrl('treeESTR').loadFromString(txtTree);
	Ctrl('treeESTR').SetXValue("");
}

function ValDateIng()
{
	if (Ctrl('f_ingreso').GetXValue() > date2str(NowDate()))
	{ 	  
	  Ctrl('f_ingreso').SetError("La fecha de ingreso no puede ser posterior a la fecha actual");
		return false;
	}
	return true;
}

function SetEstr()
{
	if(Ctrl('oi_posicion').GetXValue())
	{
		var mp, nSQL, txtTree;

		np = new NomadProxy("", ut);
		nSQL = np.SQLService();

	 	var expand = nSQL.GetOBJ(Ctrl("main").getResource("qry:EXPAND"), "<PARAM oi_posicion=\""+Ctrl("oi_posicion").GetXValue()+"\" oi_clase_org=\""+Ctrl("oi_clase_org").GetXValue()+"\"/>");
		Ctrl('treeESTR').SetXValue(expand.oi_estructura);

		txtTree = nSQL.Get(Ctrl("main").getResource("qry:ESTRUCTURA"), "<PARAM oi_clase_org=\""+Ctrl("oi_clase_org").GetXValue()+"\" id=\""+Ctrl("treeESTR").GetXValue()+"\" expand=\""+expand.expand+"\"/>");

		Ctrl('treeESTR').loadFromString(txtTree);
	}  
}

function ValidateTree()
{
	if(Ctrl('treeESTR').GetXValue() == "")
	{
		alert('Por favor seleccione la Posición en la cual se ubicará el Legajo');
		return false;
	}
	return true;
}
